import Typewriter from "typewriter-effect"
import styled from "styled-components"

const Projects = ({ id }) => {
  return <ProjectsContainer id={id}>
    <Typewriter
      onInit={(typewriter) => {
        typewriter
          .changeDelay(80)
          .typeString("Projects")
          .pauseFor(1000)
          .callFunction(state => state.elements.cursor.style.display = "none")
          .start()
      }}
    />
  </ProjectsContainer>
}

const ProjectsContainer = styled.section`
  width: 100%;
  height: 100vh;

  color: white;
  font-size: 3em;
`

export default Projects
